question.answer:
drop table if exists Works_for; drop table if exists Worker; drop table if exists Company; --------------------------------------------------------- -- Create tables --------------------------------------------------------- create table Worker( Name varchar(50) not null, City varchar(20) default null, Supervisor varchar(50) default null, constraint WrkPK primary key (Name), constraint WrkFK2 foreign key (Supervisor) references Worker(Name) on delete set null on update cascade );
create table Company( Name varchar(50) not null, City varchar(20) default null,
constraint ComPK primary key (Name) );
create table Works_for( WName varchar(50) not null, CName varchar(50) not null, Salary decimal(10,2),
constraint WfPK primary key (WName, CName), constraint WfFK foreign key (WName) references Worker(Name) on delete cascade on update cascade , constraint WfFK2 foreign key (CName) references Company(Name) on delete cascade on update cascade );

testcode.text:
---------------------------------------------------------
-- Inserting rows. This should not produce any error
-- Salary should be defined as a numeric value (float, decimal, etc.).
-- Supervisor can be NULL as the president of the company may not have any supervisor.
---------------------------------------------------------
insert into Worker values
   ('Daniel', 'Edinburgh', NULL),
   ('Juan', 'Edinburgh', NULL);

insert into Company values ('Sony', 'Glasgow');

insert into Works_for values
   ('Daniel', 'Sony', 9000);
insert into Works_for values
   ('Juan', 'Sony', 10000);


SELECT worker.name, worker.city, supervisor, wname, cname, cast(salary as integer), company.name, company.city FROM worker, works_for, company order by salary;

-- There should be a drop table for each table, in correct order
---------------------------------------------------------
-- Inserting rows. This should not produce any error
---------------------------------------------------------
insert into Worker values
   ('Daniel', 'Edinburgh', 'Daniel');  

insert into Company values
	('Sony', 'Glasgow');    

insert into Works_for values
   ('Daniel', 'Sony', 10000.00);

SELECT worker.name, worker.city, supervisor, wname, cname, company.name, company.city FROM worker, works_for, company;

extra.text:
.headers off
PRAGMA foreign_keys = ON;
drop table if exists Works_for;
drop table if exists Worker;
drop table if exists Company;

---------------------------------------------------------
-- Create tables
---------------------------------------------------------
create table Worker(
	Name varchar(50) primary key
	);


create table Company(
	Name varchar(50) primary key
	);

create table Works_for(
	WName varchar(50) not null,
	CName varchar(50) not null,
	constraint workerforFK1 foreign key (wname) 
    references worker(name),
	constraint workerforFK2 foreign key (cname) 
    references company(name) 
	);
insert into Worker values
   ('Daniel');  

insert into Company values
	('Sony');    

insert into Works_for values
   ('Daniel', 'Sony');

testcode.text:
-- Tables should be dropped only if they exist
---------------------------------------------------------
insert into Worker values
   ('Daniel', 'Edinburgh', 'Daniel');  

insert into Company values
	('Sony', 'Glasgow');    

insert into Works_for values
   ('Daniel', 'Sony', 10000.00);

SELECT worker.name, worker.city, supervisor, wname, cname, company.name, company.city FROM worker, works_for, company;

